const raw = $input.first().json.text || $input.first().json.response || '';
// Strip markdown code fences if present
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let profile;
try {
  profile = JSON.parse(cleaned);
} catch {
  profile = { search_keywords: 'developer', primary_job_title: 'developer', summary: cleaned };
}

// Merge with original form data
const form = $('CV Form').first().json;
return [{
  json: {
    ...profile,
    desired_title: form['Desired Job Title'] || profile.primary_job_title,
    location: form['Location'] || '',
    cv_text: form['CV Text']
  }
}];

// Attach candidate profile to each job item
const profile = $('Parse Profile JSON').first().json;
return $input.all().map(item => ({
  json: {
    job_id: item.json.id,
    job_title: item.json.title,
    company: item.json.company?.display_name || 'Unknown',
    location: item.json.location?.display_name || '',
    salary_min: item.json.salary_min,
    salary_max: item.json.salary_max,
    description: (item.json.description || '').substring(0, 1500),
    redirect_url: item.json.redirect_url,
    // candidate profile
    candidate_name: profile.name,
    candidate_summary: profile.summary,
    candidate_skills: profile.skills,
    candidate_experience: profile.years_experience,
    candidate_education: profile.education_level,
    candidate_languages: profile.languages,
    cv_text: profile.cv_text
  }
}));

// Combine tailored CV with job metadata
const job = $('Enrich Jobs with Profile').item.json;
const tailoredCv = $input.first().json.text || $input.first().json.response || '';
return [{
  json: {
    job_title: job.job_title,
    company: job.company,
    location: job.location,
    salary_min: job.salary_min,
    salary_max: job.salary_max,
    apply_url: job.redirect_url,
    tailored_cv: tailoredCv
  }
}];
